+// %Tag(NH_GETCACHEDPARAM_CHECK_RETURN)%
+    std::string s;
+    // 3nd time to lookup parameter server to cache parameter.
+    begin = ros::Time::now();
+    if (n.getParamCached("my_cached_param", s)) {
